def validate_api_response(response, schema):
    """
    Validates an API response against a given schema.

    The schema should define expected types and nested structures.
    - All keys present in the schema for a dictionary must be present in the response
      and validate against their respective sub-schemas.
    - All items in a list (if 'items' is defined in the schema for a list) must
      validate against the 'items' sub-schema.

    Schema structure example:
    {
        "id": {"type": int},
        "name": {"type": str},
        "is_active": {"type": bool},
        "details": {
            "type": dict,
            "properties": {
                "address": {"type": str},
                "age": {"type": int, "nullable": True} # nullable is not implemented in this version, use (int, type(None)) for type.
            }
        },
        "tags": {
            "type": list,
            "items": {"type": str}
        },
        "users": {
            "type": list,
            "items": {
                "type": dict,
                "properties": {
                    "user_id": {"type": int},
                    "user_name": {"type": str}
                }
            }
        },
        "optional_field": {"type": (str, type(None))} # Allows string or None
    }

    :param response: The API response (dictionary or list).
    :param schema: The schema dictionary to validate against.
    :return: True if the response is valid, False otherwise.
    """

    def _validate_recursive(data, schema_part):
        expected_type = schema_part.get("type")

        # If 'type' is specified in the schema, data must match it.
        # This also handles cases where data is None, but expected_type does not include type(None).
        if expected_type:
            if not isinstance(data, expected_type):
                return False

        # Handle dictionaries
        if isinstance(data, dict):
            properties_schema = schema_part.get("properties")
            if properties_schema:  # Only validate properties if a schema is provided for them
                for key, sub_schema in properties_schema.items():
                    if key not in data:
                        # Key is in schema, but not in data. Invalid (assuming all schema keys are required).
                        return False

                    # Recursively validate the value for the key
                    if not _validate_recursive(data[key], sub_schema):
                        return False
            # If 'type' was specified as dict, and properties_schema was None, it's fine.
            # If 'type' was not specified, but properties_schema was present, it's also handled.

        # Handle lists
        elif isinstance(data, list):
            items_schema = schema_part.get("items")
            if items_schema:  # Only validate items if a schema is provided for them
                for item in data:
                    # Recursively validate each item in the list
                    if not _validate_recursive(item, items_schema):
                        return False

        # For simple types (str, int, bool, float), the initial type check is sufficient.
        # No further action needed here.

        return True  # All checks passed for this `data` fragment and `schema_part`

    if not isinstance(response, dict):
        # The top-level response is expected to be a dictionary based on the schema structure.
        return False

    # Validate top-level keys in the response against the provided schema
    for key, sub_schema in schema.items():
        if key not in response:
            return False  # Missing required top-level key

        if not _validate_recursive(response[key], sub_schema):
            return False

    return True
